				static function ( $item ) {
					$label = ! empty( $item['allow_html'] ) ? wp_kses_post( $item['label'] ) : esc_html( $item['label'] );
					if ( ! empty( $item['url'] ) ) {
						return '<li><a href="' . esc_url( $item['url'] ) . '">' . $label . '</a></li>';
					}
					return '<li><span aria-current="page">' . $label . '</span></li>';
				},
				$breadcrumb_items
			)

array_map(
			static function ( $widget ) {
				$widget['render_module'] = ! empty( $widget['has_render'] )
					? 'wp/widgets/' . $widget['dir_name'] . '/render'
					: null;
				$widget['widget_module'] = ! empty( $widget['has_widget'] )
					? 'wp/widgets/' . $widget['dir_name'] . '/widget'
					: null;
				return $widget;
			},
			$raw
		)

array_filter(
				$element_pseudo_allowed,
				static function ( $pseudo_selector ) use ( $selector ) {
					/*
					 * Check if the pseudo selector is in the current selector,
					 * ensuring it is not followed by a dash (e.g., :focus should not match :focus-visible).
					 */
					return preg_match( '/' . preg_quote( $pseudo_selector, '/' ) . '(?!-)/', $selector ) === 1;
				}
			)

array_map(
			static function ( $selector ) use ( $variation_class ) {
				$selector = trim( $selector );
				$prefix   = $variation_class . ' ';

				if ( str_starts_with( $selector, $prefix ) ) {
					return substr( $selector, strlen( $prefix ) );
				}

				return $selector;
			},
			$selector_parts
		)

array_filter(
			$template_files,
			function ( $template_file ) use ( $query ) {
				return in_array( $template_file['slug'], $query['slug__in'], true );
			}
		)

array_filter(
		$registered_templates,
		function ( $registered_template ) use ( $template_files ) {
			foreach ( $template_files as $template_file ) {
				if ( $template_file['slug'] === $registered_template->slug ) {
					return false;
				}
			}
			return true;
		}
	)

array_filter(
				$registered_templates,
				function ( $registered_template ) use ( $template_files ) {
					foreach ( $template_files as $template_file ) {
						if ( $template_file['slug'] === $registered_template->slug ) {
							return false;
						}
					}
					return true;
				}
			)

